+    vector: number[],
+    k: number,
+  ) => Promise<Array<{ id: number | string; distance: number; metadata?: Record<string, unknown> }>>;
+  getStoreStatus: (deviceId: string) => Promise<{ total_vectors: number; dimension: number }>;
